{
  "sentences": [
    {
      "text": "我為了學中文來台灣。",
      "pinyin": "Wǒ wèile xué Zhōngwén lái Táiwān.",
      "pinyin_numeric": "wo3 wei4 le5 xue2 Zhong1 wen2 lai2 Tai2 wan1.",
      "translation_en": "I came to Taiwan to learn Chinese.",
      "translation_ko": "저는 중국어를 배우기 위해 대만에 왔어요."
    },
    {
      "text": "他為了工作搬到台北。",
      "pinyin": "Tā wèile gōngzuò bān dào Táiběi.",
      "pinyin_numeric": "ta1 wei4 le5 gong1 zuo4 ban1 dao4 Tai2 bei3.",
      "translation_en": "He moved to Taipei for work.",
      "translation_ko": "그는 일 때문에 타이베이로 이사했어요."
    },
    {
      "text": "她為了留學來台灣。",
      "pinyin": "Tā wèile liúxué lái Táiwān.",
      "pinyin_numeric": "ta1 wei4 le5 liu2 xue2 lai2 Tai2 wan1.",
      "translation_en": "She came to Taiwan to study abroad.",
      "translation_ko": "그녀는 유학을 위해 대만에 왔어요."
    },
    {
      "text": "我為了學中文來台灣，因為我喜歡台灣的文化。",
      "pinyin": "Wǒ wèile xué Zhōngwén lái Táiwān, yīnwèi wǒ xǐhuān Táiwān de wénhuà.",
      "pinyin_numeric": "wo3 wei4 le5 xue2 Zhong1 wen2 lai2 Tai2 wan1, yin1 wei4 wo3 xi3 huan1 Tai2 wan1 de5 wen2 hua4.",
      "translation_en": "I came to Taiwan to learn Chinese because I like Taiwanese culture.",
      "translation_ko": "저는 대만 문화를 좋아해서 중국어를 배우기 위해 대만에 왔어요."
    },
    {
      "text": "他為了當醫生來台灣上課。",
      "pinyin": "Tā wèile dāng yīshēng lái Táiwān shàngkè.",
      "pinyin_numeric": "ta1 wei4 le5 dang1 yi1 sheng1 lai2 Tai2 wan1 shang4 ke4.",
      "translation_en": "He came to Taiwan to take classes to become a doctor.",
      "translation_ko": "그는 의사가 되기 위해 대만에서 수업을 들어요."
    },
    {
      "text": "我為了工作從鄉下來城市。",
      "pinyin": "Wǒ wèile gōngzuò cóng xiāngxià lái chéngshì.",
      "pinyin_numeric": "wo3 wei4 le5 gong1 zuo4 cong2 xiang1 xia4 lai2 cheng2 shi4.",
      "translation_en": "I came from the countryside to the city for work.",
      "translation_ko": "저는 일 때문에 시골에서 도시로 왔어요."
    },
    {
      "text": "她為了學中文來台灣，已經學了半年。",
      "pinyin": "Tā wèile xué Zhōngwén lái Táiwān, yǐjīng xué le bàn nián.",
      "pinyin_numeric": "ta1 wei4 le5 xue2 Zhong1 wen2 lai2 Tai2 wan1, yi3 jing1 xue2 le5 ban4 nian2.",
      "translation_en": "She came to Taiwan to learn Chinese and has been studying for half a year.",
      "translation_ko": "그녀는 중국어를 배우기 위해 대만에 와서 벌써 반 년 동안 공부했어요."
    },
    {
      "text": "我為了考試通過努力複習。",
      "pinyin": "Wǒ wèile kǎoshì tōngguò nǔlì fùxí.",
      "pinyin_numeric": "wo3 wei4 le5 kao3 shi4 tong1 guo4 nu3 li4 fu4 xi2.",
      "translation_en": "I studied hard to pass the exam.",
      "translation_ko": "저는 시험에 합격하기 위해 열심히 복습했어요."
    },
    {
      "text": "他為了希望將來工作順利來台灣學中文。",
      "pinyin": "Tā wèile xīwàng jiānglái gōngzuò shùnlì lái Táiwān xué Zhōngwén.",
      "pinyin_numeric": "ta1 wei4 le5 xi1 wang4 jiang1 lai2 gong1 zuo4 shun4 li4 lai2 Tai2 wan1 xue2 Zhong1 wen2.",
      "translation_en": "He came to Taiwan to learn Chinese in hopes of having a smooth career in the future.",
      "translation_ko": "그는 장래에 일이 순조롭기를 바라며 대만에 와서 중국어를 배워요."
    },
    {
      "text": "我為了學中文來台灣，也為了認識台灣的朋友。",
      "pinyin": "Wǒ wèile xué Zhōngwén lái Táiwān, yě wèile rènshi Táiwān de péngyǒu.",
      "pinyin_numeric": "wo3 wei4 le5 xue2 Zhong1 wen2 lai2 Tai2 wan1, ye3 wei4 le5 ren4 shi5 Tai2 wan1 de5 peng2 you3.",
      "translation_en": "I came to Taiwan to learn Chinese and also to make Taiwanese friends.",
      "translation_ko": "저는 중국어를 배우기 위해 대만에 왔고, 또한 대만 친구들을 사귀기 위해서예요."
    }
  ]
}
